"""Load saved markdown transcripts from data/interactions/."""
from __future__ import annotations

import re
from pathlib import Path

REPO_ROOT = Path(__file__).parent.parent
DEFAULT_DIR = REPO_ROOT / "data" / "interactions" / "simulated-not-actual"

_TURN_RE = re.compile(r"^\*\*(?P<speaker>[^*]+):\*\*\s*(?P<text>.*)$")


def parse_transcript(path: Path) -> dict:
    """Return {"id", "path", "turns": [{"speaker", "text"}, ...]} for one .md file."""
    text = path.read_text(encoding="utf-8")

    if "## Transcript" in text:
        section = text.split("## Transcript", 1)[1]
        section = re.split(r"\n##\s", section, 1)[0]
    else:
        section = text

    turns: list[dict] = []
    current_speaker: str | None = None
    current_lines: list[str] = []

    def flush() -> None:
        if current_speaker is not None:
            turns.append(
                {"speaker": current_speaker, "text": "\n".join(current_lines).strip()}
            )

    for line in section.splitlines():
        m = _TURN_RE.match(line)
        if m:
            flush()
            current_speaker = m.group("speaker").strip()
            current_lines = [m.group("text")]
        elif current_speaker is not None:
            current_lines.append(line)
    flush()

    return {
        "id": path.stem,
        "path": str(path.relative_to(REPO_ROOT)),
        "turns": turns,
    }


def load_transcripts(directory: Path = DEFAULT_DIR) -> list[dict]:
    return sorted(
        (parse_transcript(p) for p in directory.glob("*.md")),
        key=lambda t: t["id"],
    )

